from flask import Flask, request,jsonify
from flask_login import login_required, current_user
from your_database_module import db, User 

app = Flask(__name__)

@app.route('/api/users/<user_id>', methods=['PUT'])
@login_required
def user_update(user_id):
    if current_user.role != "admin":
        return jsonify({"error": "Unauthorized"}), 401

    user = User.query.get(user_id)
    if not user:
        return jsonify({"error": "User not found"}), 404

    data = request.get_json()

    username = data.get('username')
    email = data.get('email')
    role = data.get('role')
    account_status = data.get('account_status')
    subscription_tier = data.get('subscription_tier')

    if username:
        user.username = username
    if email:
        user.email = email
    if role in ['user', 'moderator', 'admin']:
        user.role = role
    if account_status in ['active', 'suspended']:
        user.account_status = account_status
    if subscription_tier in ['free', 'pro', 'enterprise']:
        user.subscription_tier = subscription_tier

    db.session.commit()
    return jsonify({"message": "User record has been updated"}), 200

if __name__ == "__main__":
    app.run(debug=True)